

export default function LoginPage() {
    const [loader, setLoader] = useState(false);
      const router = useRouter();
      const [form, setForm] = useState({
        name: "",
        email: "",
        password: "",
      });
    
      const handleChanges = (e) => {
        setForm((prev) => ({
          ...prev,
          [e.target.name]: e.target.value,
        }));
      };
    
      const submitHandler = (e) => {
        e.preventDefault();
        setLoader(true);
        client
          .post("user/register", form)
          .then((response) => {
            notify(response.data.masg, response.data.success);
            console.log(response, "user response");
    
            if (response.data.success) {
              setForm({});
              router.push(`/otp-verify?email=${form.email}`);
            }
          })
          .catch((error) => {
            if (error) {
              notify("Internal server error", false);
            }
          })
          .finally(() => {
            setLoader(false);
          });
      };
  return (
    <div className="min-h-screen bg-[#f4f7f7] flex items-center justify-center px-4 py-10">
      <div className="w-full max-w-xl bg-white rounded-[28px] shadow-lg p-8 md:p-10 border border-gray-100">
        <div className="text-center mb-8">
          <h1 className="text-4xl font-bold text-gray-900 tracking-tight">
            Welcome Back
          </h1>
          <p className="text-gray-500 mt-3 text-sm md:text-base">
            Login to continue shopping on IShop
          </p>
        </div>

        <form className="space-y-5">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              Email Address
            </label>
            <input
              type="email"
              placeholder="Enter your email"
              className="w-full border border-gray-300 rounded-xl px-4 py-2.5 text-sm outline-none focus:ring-2 focus:ring-[#01A49E] focus:border-transparent transition"
            />
          </div>

          <div>
            <div className="flex items-center justify-between mb-2">
              <label className="block text-sm font-medium text-gray-700">
                Password
              </label>

              <button
                type="button"
                className="text-sm text-[#01A49E] hover:underline"
              >
                Forgot Password?
              </button>
            </div>

            <input
              type="password"
              placeholder="Enter your password"
              className="w-full border border-gray-300 rounded-xl px-4 py-2.5 text-sm outline-none focus:ring-2 focus:ring-[#01A49E] focus:border-transparent transition"
            />
          </div>

          <button
            type="submit"
            className="w-full bg-[#01A49E] text-white py-3 rounded-xl font-semibold hover:opacity-90 transition-all duration-300"
          >
            Login
          </button>
        </form>

        <div className="mt-6 text-center text-sm text-gray-600">
          Don&apos;t have an account?{' '}
          <span className="text-[#01A49E] font-semibold cursor-pointer hover:underline">
            Register
          </span>
        </div>
      </div>
    </div>
  );
}
